# Base module with abstract class and interface

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Animal:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def speak(self) -> str: ...

    @virtual
    def describe(self) -> str:
        return f"{self.name} is an animal"

